'''
Debug util for testing encoded binary returns
'''

import base64

# Base64 encoded string
fhir = {
    "data": ""
}
file_data = base64.b64decode(fhir["data"])

# Save the decoded data into a file
output_file = "output_file.zip"  # Name your output file accordingly
with open(output_file, "wb") as file:
    file.write(file_data)

print(f"File has been saved as: {output_file}")